int main()
{
    // srand(unsigned(time(0)));
    // ofstream in("11.in"),out("11.out");
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        a[x]++;
        b[y]++;
    }
    for(long long i=0;i<=m;i++)
    {
        for(long long j=0;j<=m;j++)
        {
            c[i+j]+=a[i]*a[j];
            c[i+j+1]-=b[i]*b[j];
        }
    }
    long long sum=0;
    for(long long i=0;i<=2*m;i++)
    {
        sum+=c[i];
        printf("%lld\n",sum);
    }
    return 0;
}
